const rateLimit = require('express-rate-limit');
const cors = require('cors');

app.disable('x-powered-by');
app.use(helmet());
app.use(cors({ origin: process.env.ALLOWED_ORIGIN, methods: ['GET'] }));
app.use(rateLimit({ windowMs: 60_000, max: 100 }));
```

## 4. Information Disclosure in `/users`

**Issue:** The endpoint returns email addresses with no authn/authz. Even for test data, this is a pattern that leaks PII.

**Suggestion:**
