const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { param, validationResult } = require('express-validator');

const app = express();
const PORT = Number(process.env.PORT) || 3000;
const isProd = process.env.NODE_ENV === 'production';

// --- Security middleware ---
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '10kb' }));          // cap body size (DoS)
app.use(rateLimit({ windowMs: 60_000, max: 100 })); // basic rate limit

// --- Routes ---
app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get(
  '/users/:id',
  param('id').isInt({ min: 1 }).toInt(),
  (req, res, next) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ error: 'Invalid id' });
    }
    // ... lookup
    next();
  }
);

// --- 404 handler ---
app.use((_req, res) => res.status(404).json({ error: 'Not found' }));

// --- Centralized error handler (must be last) ---
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  console.error(err); // send to real logger in prod (pino/winston)
  res.status(err.status || 500).json({
    error: isProd ? 'Internal server error' : err.message,
  });
});

// --- Graceful shutdown + process guards ---
if (require.main === module) {
  const server = app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });

  const shutdown = (signal) => {
    console.log(`${signal} received, closing server...`);
    server.close(() => process.exit(0));
    setTimeout(() => process.exit(1), 10_000).unref(); // force-exit fallback
  };
  process.on('SIGTERM', () => shutdown('SIGTERM'));
  process.on('SIGINT', () => shutdown('SIGINT'));
  process.on('unhandledRejection', (reason) => { throw reason; });
  process.on('uncaughtException', (err) => {
    console.error('uncaughtException', err);
    shutdown('uncaughtException');
  });
}

module.exports = app;
```

---

## Summary of Security Wins

| Concern | Mitigation |
|---|---|
| Stack-trace leaks | Central error handler that hides messages in prod |
| Header-based attacks (XSS, clickjacking, MIME sniffing) | `helmet()` |
| `X-Powered-By` fingerprinting | `app.disable('x-powered-by')` |
| Body-size DoS | `express.json({ limit: '10kb' })` |
| Brute-force / scraping | `express-rate-limit` |
| Injection via path/query params | `express-validator` with `.isInt()`, `.escape()`, etc. |
| Crash-on-error exits | Graceful `SIGTERM`/`SIGINT` handling |
| Silent promise rejections | `unhandledRejection` handler |
| Hard-coded config | `process.env.PORT`, `NODE_ENV` |
| Test isolation | `if (require.main === module)` guard around `listen` |

## Follow-ups to Consider
1. **AuthN/AuthZ** on `/users` — currently anyone can list users with emails. Add JWT/session auth and return only fields the caller is entitled to see.
2. **CORS** — add `cors()` with an explicit allow-list rather than `*`.
3. **Structured logging** — replace `console.log` with `pino` or `winston` (request IDs, redacted PII).
4. **HTTPS/TLS** — terminate at a reverse proxy (nginx, ALB) and set `app.set('trust proxy', 1)` so rate-limit sees real client IPs.
5. **Dependency hygiene** — run `npm audit` / Dependabot; pin versions in `package-lock.json`.

