app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// Centralized error middleware — must have 4 args
app.use((err, req, res, next) => {
  // Log server-side with a request correlation id, do NOT leak internals
  console.error({ msg: err.message, stack: err.stack, path: req.path });
  const status = err.status || 500;
  res.status(status).json({ error: status === 500 ? 'Internal Server Error' : err.message });
});

process.on('unhandledRejection', (reason) => { console.error('unhandledRejection', reason); });
process.on('uncaughtException', (err) => { console.error('uncaughtException', err); process.exit(1); });
```

## 2. No input validation

**Issue:** `/users` currently takes no input, but any realistic version will. There's no schema validation layer, and `express.json()` isn't even registered — so future `POST`/`PUT` bodies would silently be `undefined`.

**Recommendation:** Add a validator (e.g. `zod`, `joi`, or `express-validator`) and a body-size cap:
