const cors = require('cors');

app.use(helmet());                                // sets secure headers (CSP, HSTS, etc.)
app.use(cors({ origin: process.env.ALLOWED_ORIGIN })); // never use `*` with credentials
app.use(express.json({ limit: '10kb' }));         // prevents large-payload DoS
app.disable('x-powered-by');                      // don't leak framework identity
