const helmet  = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '100kb', strict: true }));
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (_req, res) => {
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

app.use((_req, res) => res.status(404).json({ error: 'Not found' }));
app.use((err, _req, res, _next) => {
  console.error(err);
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production' ? 'Internal server error' : err.message,
  });
});

const port = Number(process.env.PORT) || 3000;
const server = app.listen(port, () => console.log(`Server running on port ${port}`));

for (const sig of ['SIGTERM', 'SIGINT']) {
  process.on(sig, () => server.close(() => process.exit(0)));
}
process.on('unhandledRejection', (r) => console.error('unhandledRejection', r));

module.exports = app;
```

## Priority order if you want to pick incrementally

1. `helmet` + `disable('x-powered-by')` — one-line wins.
2. Error-handling middleware + `unhandledRejection` hook — prevents crashes/leaks.
3. Body size limit on `express.json`.
4. Rate limiting on public routes.
5. Schema-based validation before any route reads input.
6. Remove `email` from the public users response (or gate behind auth).
7. Graceful shutdown + `process.env.PORT`.

